def test_employees_all_cases(api_client, merged_test_data):
    """
    Check /employees with all cases from endpoint_test_data.json, validate schema,
    expected status code, handle boundary and negative scenarios.
    """
    data = merged_test_data(_endpoint_data_path)

    for item in data:
        query_params = {}

        if "searchString" in item:
            query_params["searchString"] = item["searchString"]
        elif "name" in item:
            # Boundary: valid search by name
            query_params["searchString"] = item["name"]
        elif "id" in item:
            # Test search by id
            query_params["searchString"] = item["id"]

        expected_status = item.get("statusCode", 200)

        resp = api_client.get(
            _ENDPOINT,
            params=query_params
        )

        assert resp.status_code == expected_status, (
            f"Status code mismatch for input {query_params}: Expected {expected_status}, got {resp.status_code}"
        )

        if expected_status == 200 or expected_status == 201:
            result = validator.validate_schema_by_response(_ENDPOINT, _METHOD, "200", resp)
            assert result["valid"], f"Schema validation failed: {result.get('message', '')}"

            resp_json = resp.json()
            assert isinstance(resp_json, list), "Response should be a list"
            for employee in resp_json:
                for field in ("jobTitle", "name", "email"):
                    assert field in employee, f"Missing required field '{field}' in employee: {employee}"
        elif expected_status == 400:
            # For bad input, confirm schema or meaningful message
            assert 'Bad input' in resp.text or resp.reason, (
                f"Bad input scenario not handled properly: {resp.text}"
            )
        else:
            # For default/other errors, should not be 2xx
            assert not (200 <= resp.status_code < 300), (
                f"Unexpected 2xx in error case: {resp.status_code}"
            )


